export const cartReducer = (state ={ cartItems :[]},action)=>{
    switch (action.type)
    {
        case 'ADD_TO_CART':
            const alreadyExists=state.cartItems.find(item=>item._item._id===action.payload._id);
            if(alreadyExists)
            {
                return {}
            }
            return {
                ...state,
                cartItems :[...state.cartItems,action.payload]
            }

    default : return state
}
}
